def _deep_merge_feature(old_feature, new_feature):
    """
    Recursively merge ``new_feature`` into ``old_feature`` when both are dictionaries,
    or ``Sequence`` objects whose ``feature`` attribute is a dictionary.
    Otherwise ``new_feature`` simply replaces ``old_feature``.
    """
    if isinstance(old_feature, dict) and isinstance(new_feature, dict):
        for key, value in new_feature.items():
            old_feature[key] = _deep_merge_feature(old_feature[key], value) if key in old_feature else value
        return old_feature
    elif (
        isinstance(old_feature, Sequence)
        and isinstance(new_feature, Sequence)
        and isinstance(old_feature.feature, dict)
        and isinstance(new_feature.feature, dict)
    ):
        old_feature.feature = _deep_merge_feature(old_feature.feature, new_feature.feature)
        return old_feature
    else:
        return new_feature


